/**
 * @file Generating Python for turtle blocks.
 */

// Former goog.module ID: Blockly.Python.turtle

import type {Block} from '../../core/block.js';
import type {PythonGenerator} from './python_generator.js';
import {Order} from './python_generator.js';

export function turtle_create(block: Block, generator: PythonGenerator): [string, Order] {
    (generator as AnyDuringMigration).definitions_['import_turtle'] = 'import turtle'

    let code = 'turtle.Turtle()\n'
    return [code, Order.ATOMIC]
}
export function turtle_move(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['import_turtle'] = 'import turtle'

    let VALUE = generator.valueToCode(block, 'VALUE', Order.NONE) || '0';
    let direction = block.getFieldValue('direction')
    let distance = generator.valueToCode(block, 'distance', Order.NONE) || '0';

    let code = `${VALUE}.${direction}(${distance})\n`
    return code
}
