export function turtle_draw_circle(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['import_turtle'] = 'import turtle'

    let VALUE = generator.valueToCode(block, 'VALUE', Order.NONE) || '0';
    let radius = generator.valueToCode(block, 'radius', Order.NONE) || '0';
    let extent = generator.valueToCode(block, 'extent', Order.NONE) || '0';
    let steps = generator.valueToCode(block, 'steps', Order.NONE) || '0';
    let params = ''
    if (+radius !== 0) params += radius
    if (+extent !== 0) params += `, ${extent}`
    if (+steps !== 0) params += `, ${steps}`
    let code = `${VALUE}.circle(${params})\n`
    return code
}
