/**
 * @file Generating Python for car blocks.
 */

// Former goog.module ID: Blockly.Python.car

import type {Block} from '../../core/block.js';
import type {PythonGenerator} from './python_generator.js';
import {Order} from './python_generator.js';

export function extension_car_initialization(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_sk_car.motor_import_Control_Motor'] =
    'from sk_car.motor import Control_Motor';

    let speed = block.getFieldValue('speed');
    let code = `Control_Motor.GS_run(${speed})\n`
	return code
}
export function extension_car_column_power(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_sk_car.motor_import_Control_Motor'] =
    'from sk_car.motor import Control_Motor';

    let direction = block.getFieldValue('direction');
	let speed = block.getFieldValue('speed');
	let code = ''
	if (direction === 'front') {
		code = `Control_Motor.Advance(${speed})`
	} else if (direction === 'after') {
		code = `Control_Motor.Back(${speed})`
	}
	return code + '\n'
}
export function extension_car_column_power_time(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_sk_car.motor_import_Control_Motor'] =
    'from sk_car.motor import Control_Motor';

    let direction = block.getFieldValue('direction');
	let speed = block.getFieldValue('speed');
	let ms = block.getFieldValue('ms');
	let code = ''
	if (direction === 'front') {
		code = `Control_Motor.Advance(${speed}, ${ms / 1000})`
	} else if (direction === 'after') {
		code = `Control_Motor.Back(${speed}, ${ms / 1000})`
	}
	return code + '\n'
}
export function extension_car_driving_power(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_sk_car.motor_import_Control_Motor'] =
    'from sk_car.motor import Control_Motor';

	let lt = block.getFieldValue('lt');
	let rt = block.getFieldValue('rt');
	let lb = block.getFieldValue('lb');
	let rb = block.getFieldValue('rb');
	let code = ''
	code += `Control_Motor.GS_run(${lt}, ${rt}, ${lb}, ${rb})\n`
	return code
}
