export function extension_car_camera_angle(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_sk_car.motor_import_Control_Motor'] =
    'from sk_car.motor import Control_Motor';

    let direction = block.getFieldValue('direction');
	let angle = block.getFieldValue('angle');
	let code = `Control_Motor.set_gimbal(${['top', 'bottom', 'left', 'right'].indexOf(direction)}, ${angle})\n`
	return code
}
export function extension_car_stop(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_sk_car.motor_import_Control_Motor'] =
    'from sk_car.motor import Control_Motor';
    
    let code = `Control_Motor.close()\n`
	return code
}
