// Former goog.module ID: Blockly.Python.mechanicalArm

import type {Block} from '../../core/block.js';
import type {PythonGenerator} from './python_generator.js';
import {Order} from './python_generator.js';

export function mechanical_arm_initialization(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_arm_module_import_Control_Arm'] = 'from arm_module import Control_Arm'
    let code = '\n'
    return code
}
export function mechanical_arm_reset(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_arm_module_import_Control_Arm'] = 'from arm_module import Control_Arm'

    let code = 'Control_Arm.reset_position()\n'
    return code
}
export function mechanical_arm_servo_pulse(block: Block, generator: PythonGenerator): [string, Order] {
    (generator as AnyDuringMigration).definitions_['from_arm_module_import_Control_Arm'] = 'from arm_module import Control_Arm'

    let servo = block.getFieldValue('servo')
    let code = `Control_Arm.servo_get_position(${servo})\n`
    return [code, Order.ATOMIC]
}
