/**
 * 限位情况下(不限位，不限制)
 * 1: 0-2400
 * 2: 0-1679
 * 3: 1081-2400
 */
export function mechanical_arm_servo_parameters(block: Block, generator: PythonGenerator) {
    (generator as AnyDuringMigration).definitions_['from_arm_module_import_Control_Arm'] = 'from arm_module import Control_Arm'

    let servo = block.getFieldValue('servo')
    let pulse = block.getFieldValue('pulse')
    let ms = block.getFieldValue('ms')
    let bol = block.getFieldValue('bol')
    let code = ''
    if (bol) {
        if (servo === 1 && pulse < 0 && pulse > 2400) alert('舵机1脉冲值[0, 2400]')
        else if (servo === 2 && pulse < 0 && pulse > 1679) alert('舵机2脉冲值[0, 1679]')
        else if (servo === 3 && pulse < 1081 && pulse > 2400) alert('舵机3脉冲值[1081, 2400]')
        else code += `Control_Arm.servo_set_position(${servo}, ${pulse}, ${ms}, ${bol})\n`
    } else {
        code += `Control_Arm.servo_set_position(${servo}, ${pulse}, ${ms}, ${bol})\n`
    }
    return code
}
